// === Preparar Paths ===
// CAMINHO LEVE DE MEMORIA (corrige o OOM "n8n may have run out of memory").
// Antes: montava um filter_complex de transicoes suaves com os 14 clips como inputs
// simultaneos -> decodificava os 14 videos 1080x1920 ao mesmo tempo e estourava a RAM.
// Agora: (1) escreve cada clip em /tmp descartando o buffer; (2) concatena com o
// CONCAT DEMUXER (stream copy = nao reabre todos os videos); (3) aplica o CTA e a
// musica opcional em UMA UNICA passada de re-encode sequencial (1 input de video)
// com -preset ultrafast e -threads 2 para limitar o pico de memoria/CPU.
// Trade-off: perdemos a transicao suave entre clips, mas ganhamos estabilidade no servidor.
// ASYNC: usa exec via wrapper Promise manual sobre child_process.exec (sem o modulo util).
const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
function execAsync(cmd, opts) {
  return new Promise(function (resolve, reject) {
    exec(cmd, opts, function (err, stdout, stderr) {
      if (err) { reject(err); } else { resolve({ stdout: stdout, stderr: stderr }); }
    });
  });
}
const EXEC_OPTS = { timeout: 300000, maxBuffer: 1024 * 1024 * 64 };
const NL = String.fromCharCode(10);
const BS = String.fromCharCode(92);
const TMP = '/tmp';

function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}

async function getBuf(idx, prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(idx, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}

// 1) Le cada clip (binary "data") em ordem e escreve em /tmp.
//    Para nao acumular memoria, NAO guardamos os buffers: escreve e descarta (buf = null).
const items = $input.all();
const clipPaths = [];
let articleTitle = 'video_dje';
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  if (items[i].json && items[i].json.articleTitle) articleTitle = items[i].json.articleTitle;
  let buf = await getBuf.call(this, i, 'data', bin);
  if (!buf) continue;
  const p = `${TMP}/seg_${i}.mp4`;
  fs.writeFileSync(p, buf);
  buf = null; // libera a referencia do buffer imediatamente
  clipPaths.push(p);
}

if (clipPaths.length === 0) {
  throw new Error('Nenhum clip disponivel para concatenar.');
}

// 2) Concatena com o CONCAT DEMUXER (stream copy, leve). Os clips tem o mesmo
//    codec/params (gerados igualmente pelo "Preparar Arquivos"), entao -c copy funciona.
//    O list.txt usa quebras de linha via String.fromCharCode(10) (PASTE-SAFE).
const listPath = `${TMP}/list.txt`;
const listLines = clipPaths.map(function (p) { return "file '" + p + "'"; });
fs.writeFileSync(listPath, listLines.join(NL) + NL);
const concatPath = `${TMP}/concat.mp4`;
await execAsync(`ffmpeg -y -f concat -safe 0 -i "${listPath}" -c copy "${concatPath}"`, EXEC_OPTS);

// CTA (drawtext): mesmo texto/posicao de antes, com a fonte DejaVu/Liberation detectada.
const FONT = (function () {
  const fontes = [
    '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf'
  ];
  for (const f of fontes) { try { if (fs.existsSync(f)) return f; } catch (e) {} }
  return null;
})();
const fontPart = FONT ? `fontfile='${FONT}':` : '';
const ctaText = 'Orcamento gratis' + BS + ': WhatsApp (11) 5891.6837';
const ctaDraw = `drawtext=${fontPart}text='${ctaText}':fontcolor=white:fontsize=48:box=1:boxcolor=black@0.6:boxborderw=18:x=(w-text_w)/2:y=h*0.06:enable='gte(t,0)'`;

// 3) Musica de fundo opcional (URL do formulario, baixada via wget como antes).
let musicaUrl = '';
try {
  const fdata = $('Formulario de Video').first().json || {};
  musicaUrl = String(fdata['Musica de Fundo (URL)'] || '').trim();
} catch (e) { musicaUrl = ''; }

const musicPath = `${TMP}/bg_music.mp3`;
let temMusica = false;
if (musicaUrl) {
  try {
    await execAsync(`wget -q --user-agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36" -O "${musicPath}" "${musicaUrl}"`, { timeout: 120000, maxBuffer: 1024 * 1024 * 16 });
    temMusica = (function () { try { return fs.existsSync(musicPath) && fs.statSync(musicPath).size > 4096; } catch (e) { return false; } })();
  } catch (e) { temMusica = false; }
}

// 4) Aplica o CTA (+ musica opcional) em UMA UNICA passada de re-encode (1 input de video,
//    sequencial = leve). -preset ultrafast e -threads 2 limitam o pico de memoria/CPU.
const finalPath = `${TMP}/final.mp4`;
let sucesso = false;
try {
  if (temMusica) {
    await execAsync(`ffmpeg -y -i "${concatPath}" -stream_loop -1 -i "${musicPath}" -filter_complex "[0:v]${ctaDraw}[v];[1:a]volume=0.12[bg];[0:a][bg]amix=inputs=2:duration=first:dropout_transition=2:normalize=0[a]" -map "[v]" -map "[a]" -c:v libx264 -preset ultrafast -threads 2 -pix_fmt yuv420p -c:a aac -b:a 192k -shortest -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  } else {
    await execAsync(`ffmpeg -y -i "${concatPath}" -vf "${ctaDraw}" -c:v libx264 -preset ultrafast -threads 2 -pix_fmt yuv420p -c:a aac -b:a 192k -movflags +faststart "${finalPath}"`, EXEC_OPTS);
  }
  sucesso = fs.existsSync(finalPath) && fs.statSync(finalPath).size > 0;
} catch (e) {
  sucesso = false;
}

// 5) Fallback gracioso: se o re-encode com CTA falhar, devolve o concat puro (sem CTA)
//    em vez de quebrar o workflow.
const saidaPath = sucesso ? finalPath : concatPath;

// 6) Retorno final: json { articleTitle, fileName } + binary { data }.
const finalBuf = fs.readFileSync(saidaPath);
const nomeArquivo = `${articleTitle}.mp4`;
return [{
  json: { articleTitle: articleTitle, fileName: nomeArquivo },
  binary: { data: await this.helpers.prepareBinaryData(finalBuf, nomeArquivo, 'video/mp4') }
}];
